export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteInput {
  items: Item[];
}

export interface QuoteResult {
  premium: number;
}

export function quote(_input: QuoteInput): QuoteResult {
  return undefined as unknown as QuoteResult;
}
